     4→ */
     5→
     6→class GameEngine {
     7→    constructor() {
     8→        this.board = new Board();
     9→        this.currentTurn = PieceColor.WHITE;
    10→        this.gameState = { status: 'playing', winner: null, inCheck: false };
    11→        this.moveHistory = [];
    12→        this.capturedPieces = { white: [], black: [] };
    13→        this.pendingPromotion = null;
    14→
    15→        // Callbacks for UI updates
    16→        this.onStateChange = null;
    17→        this.onMove = null;
    18→        this.onCapture = null;
    19→        this.onGameOver = null;
    20→    }
    21→
    22→    /**
    23→     * Initialize a new game
    24→     */
    25→    init() {
    26→        this.board.initialize();
    27→        this.currentTurn = PieceColor.WHITE;
    28→        this.gameState = { status: 'playing', winner: null, inCheck: false };
    29→        this.moveHistory = [];
    30→        this.capturedPieces = { white: [], black: [] };
    31→        this.pendingPromotion = null;
