    36→    /**
    37→     * Make a move
    38→     * @param {Object} from - Source position {row, col}
    39→     * @param {Object} to - Destination position {row, col}
    40→     * @param {string} promotionPiece - Type of piece for pawn promotion
    41→     * @returns {Object} Move result {success, captured, moveType}
    42→     */
    43→    makeMove(from, to, promotionPiece = PieceType.QUEEN) {
    44→        // Validate move
    45→        const validationResult = Rules.validateMove(this.board, from, to, this.currentTurn);
    46→
    47→        if (!validationResult.valid) {
    48→            return { success: false, reason: validationResult.reason };
    49→        }
    50→
    51→        const piece = this.board.getPieceAt(from.row, from.col);
    52→        const captured = this.board.getPieceAt(to.row, to.col);
    53→        const moveType = validationResult.moveType;
    54→
    55→        // Handle pawn promotion
    56→        if (moveType === 'promotion') {
    57→            this.pendingPromotion = { from, to };
    58→            return { success: true, requiresPromotion: true };
    59→        }
    60→
    61→        // Execute the move
    62→        return this.executeMove(from, to, moveType, captured);
    63→    }
    64→
    65→    /**
    66→     * Execute a move on the board
    67→     * @param {Object} from - Source position
    68→     * @param {Object} to - Destination position
    69→     * @param {string} moveType - Type of move
    70→     * @param {Piece} captured - Captured piece (if any)
    71→     * @returns {Object} Move result
    72→     */
    73→    executeMove(from, to, moveType, captured) {
    74→        const piece = this.board.getPieceAt(from.row, from.col);
    75→        let actualCaptured = captured;
    76→
    77→        // Handle special moves
    78→        if (moveType === 'castling') {
    79→            this.executeCastling(from, to);
    80→        } else if (moveType === 'enpassant') {
    81→            actualCaptured = this.executeEnPassant(from, to);
    82→        } else {
    83→            // Normal move
    84→            this.board.movePiece(from, to);
    85→        }
    86→
    87→        // Handle pawn promotion (if specified)
    88→        if (this.pendingPromotion && moveType === 'promotion') {
    89→            this.executePromotion(to, this.pendingPromotion.pieceType || PieceType.QUEEN);
    90→            this.pendingPromotion = null;
    91→        }
    92→
    93→        // Track captured pieces
    94→        if (actualCaptured) {
    95→            const capturingColor = piece.color;
    96→            const capturedColor = actualCaptured.color;
    97→            this.capturedPieces[capturedColor].push(actualCaptured);
    98→
    99→            if (this.onCapture) {
   100→                this.onCapture(actualCaptured, to);
   101→            }
   102→        }
   103→
   104→        // Update move history
   105→        this.recordMove(from, to, piece, actualCaptured, moveType);
   106→
   107→        // Switch turns
   108→        this.switchTurn();
   109→
   110→        // Update game state
   111→        this.updateGameState();
   112→
   113→        // Notify listeners
   114→        this.notifyStateChange();
   115→
   116→        if (this.onMove) {
   117→            this.onMove(from, to, piece, actualCaptured);
   118→        }
   119→
   120→        if (this.gameState.status !== 'playing' && this.onGameOver) {
