   125→            success: true,
   126→            captured: actualCaptured,
   127→            moveType: moveType
   128→        };
   129→    }
   130→
   131→    /**
   132→     * Execute castling move
   133→     * @param {Object} from - King position
   134→     * @param {Object} to - King destination
   135→     */
   136→    executeCastling(from, to) {
