   159→        const captureCol = to.col;
   160→        const captured = this.board.getPieceAt(captureRow, captureCol);
   161→
   162→        // Remove captured pawn
   163→        this.board.setPieceAt(captureRow, captureCol, null);
   164→
   165→        // Move capturing pawn
   166→        this.board.movePiece(from, to);
   167→
   168→        return captured;
   169→    }
   170→
   171→    /**
   172→     * Execute pawn promotion
