   174→     * @param {string} newType - Type of piece to promote to
   175→     */
   176→    executePromotion(pos, newType) {
   177→        const pawn = this.board.getPieceAt(pos.row, pos.col);
   178→
   179→        if (pawn && pawn.type === PieceType.PAWN) {
   180→            const newPiece = createPiece(pawn.color, newType, pos.row, pos.col);
   181→            newPiece.hasMoved = true;
   182→            this.board.setPieceAt(pos.row, pos.col, newPiece);
